        BF16["BF16: 1 sign + 8 exp + 7 mantissa<br/>Range: same as FP32<br/>Precision: ~2 decimal digits"]
        TF32["TF32: 1 sign + 8 exp + 10 mantissa<br/>Range: same as FP32<br/>Precision: ~3 decimal digits"]
