        Code["@property<br/>def data(self):<br/>    return self._data<br/><br/>@data.setter<br/>def data(self, value):<br/>    self._data = value<br/><br/>@data.deleter<br/>def data(self):<br/>    print('Cleaning up...')<br/>    del self._data"]
